      state <= full_state[11:0] ^
              {full_state[10:0],1'b0} ^
              {full_state[9:0],2'b0} ^
              {full_state[8:0],3'b0} ^
              {full_state[3:0],8'b0} ^
              {full_state[2:0],9'b0};
    end
  end

  assign crc12 = state;

endmodule

