	assign vcc = 1'b1;
	assign unknown = 1'bx;

	reg \fstate_state2_regout ;
	reg \fstate_state3_regout ;

	wire \Dout_combout ;

	// Process for fstate.state2 register
	always @(posedge clock or posedge reset) begin
		if (reset)
			\fstate_state2_regout <= 1'b0;
		else
			\fstate_state2_regout <= Din;
