module mg_07027(Address, Din, Clock, Reset, WriteEnabled, Dout);
input [5:0] Address; 
  input [6:0] Din; 
  input Reset; 
  input Clock, WriteEnabled; 
  output [6:0] Dout; 
  reg [6:0] Data [39:0]; 
  always@(posedge Clock or posedge Reset) 
  if (Reset == 1) begin 
  Data[0] <= "E"; 
  Data[1] <= "C"; 
  Data[2] <= "E"; 
  Data[3] <= "3"; 
  Data[4] <= "3"; 
  Data[5] <= "3"; 
