module origen_105120 (
    input [1:0] ALUsrcA_controll_id,
    input [1:0] ALUsrcB_controll_id,
    input [2:0] register_invalid [0:7],
    input [2:0] ra,
    input [2:0] rb,
    output reg [1:0] forwardingA_controll_id,
    output reg [1:0] forwardingB_controll_id,
    output reg [1:0] forwarding_ra_controll_id,
    output reg [1:0] forwarding_rb_controll_id,
    output reg forwarding_lock_controll
);

always @(*) begin
    // ALU input A forwarding
    if (ALUsrcA_controll_id == 2'b00) begin
        case (register_invalid[rb])
            3'b001: forwardingA_controll_id = 2'b01;
            3'b010: forwardingA_controll_id = 2'b10;
            default: forwardingA_controll_id = 2'b00;
        endcase
    end else begin
        forwardingA_controll_id = 2'b00;
    end

    // ALU input B forwarding
    if (ALUsrcB_controll_id == 2'b00) begin
        case (register_invalid[ra])
            3'b001: forwardingB_controll_id = 2'b01;
            3'b010: forwardingB_controll_id = 2'b10;
            default: forwardingB_controll_id = 2'b00;
        endcase
    end else begin
        forwardingB_controll_id = 2'b00;
    end

    // Register read port ra forwarding
    case (register_invalid[ra])
        3'b001: forwarding_ra_controll_id = 2'b01;
        3'b010: forwarding_ra_controll_id = 2'b10;
        default: forwarding_ra_controll_id = 2'b00;
    endcase

    // Register read port rb forwarding
    case (register_invalid[rb])
        3'b001: forwarding_rb_controll_id = 2'b01;
        3'b010: forwarding_rb_controll_id = 2'b10;
        default: forwarding_rb_controll_id = 2'b00;
    endcase

    // Pipeline stall control
    forwarding_lock_controll = (register_invalid[rb] == 3'b011) ? 1'b1 : 1'b0;
end

endmodule

