module origen_064037 #(
    parameter DEAD_TIME_NUM_CLKS_RISE_EDGE = 8,
    parameter DEAD_TIME_NUM_CLKS_FALL_EDGE = 6,
    parameter CLOCK_FREQUENCY = 50_000_000
) (
    input wire IN_SIGNAL,
    input wire IN_CLOCK,
    output wire OUT_DEBOUNCE_SIGNAL
);

    reg REG_DEAD_TIME_RISE_EDGE_WAIT;
    reg REG_DEAD_TIME_FALL_EDGE_WAIT;
    reg REG_SET_SIGNAL;
    reg [$clog2(DEAD_TIME_NUM_CLKS_RISE_EDGE)-1:0] REG_COUNT_DEAD_TIME_RISE_EDGE;
    reg [$clog2(DEAD_TIME_NUM_CLKS_FALL_EDGE)-1:0] REG_COUNT_DEAD_TIME_FALL_EDGE;

    always @(posedge IN_CLOCK) begin
        if (IN_SIGNAL && !REG_SET_SIGNAL && !REG_DEAD_TIME_RISE_EDGE_WAIT) begin
            REG_DEAD_TIME_RISE_EDGE_WAIT <= 1'b1;
            REG_COUNT_DEAD_TIME_RISE_EDGE <= 0;
        end
        else if (!IN_SIGNAL && REG_SET_SIGNAL && !REG_DEAD_TIME_FALL_EDGE_WAIT) begin
            REG_DEAD_TIME_FALL_EDGE_WAIT <= 1'b1;
            REG_COUNT_DEAD_TIME_FALL_EDGE <= 0;
        end
        else if (REG_DEAD_TIME_RISE_EDGE_WAIT) begin
            if (REG_COUNT_DEAD_TIME_RISE_EDGE == DEAD_TIME_NUM_CLKS_RISE_EDGE - 1) begin
                REG_SET_SIGNAL <= 1'b1;
                REG_DEAD_TIME_RISE_EDGE_WAIT <= 1'b0;
            end
            else if (IN_SIGNAL) begin
                REG_COUNT_DEAD_TIME_RISE_EDGE <= REG_COUNT_DEAD_TIME_RISE_EDGE + 1;
            end
            else begin
                REG_DEAD_TIME_RISE_EDGE_WAIT <= 1'b0;
            end
        end
        else if (REG_DEAD_TIME_FALL_EDGE_WAIT) begin
            if (REG_COUNT_DEAD_TIME_FALL_EDGE == DEAD_TIME_NUM_CLKS_FALL_EDGE - 1) begin
                REG_SET_SIGNAL <= 1'b0;
                REG_DEAD_TIME_FALL_EDGE_WAIT <= 1'b0;
            end
            else if (!IN_SIGNAL) begin
                REG_COUNT_DEAD_TIME_FALL_EDGE <= REG_COUNT_DEAD_TIME_FALL_EDGE + 1;
            end
            else begin
                REG_DEAD_TIME_FALL_EDGE_WAIT <= 1'b0;
            end
        end
    end

    assign OUT_DEBOUNCE_SIGNAL = REG_SET_SIGNAL;

endmodule

