module rtlpp_05182 (
    address,
    byteenable,
    chipselect,
    clk,
    clken,
    freeze,
    reset,
    reset_req,
    write,
    writedata,
    readdata
);

  parameter INIT_FILE = "nios_system_onchip_memory2_0.hex";

  output reg [31:0] readdata;
  input [12:0] address;
  input [3:0] byteenable;
  input chipselect;
  input clk;
  input clken;
  input freeze;
  input reset;
  input reset_req;
  input write;
  input [31:0] writedata;

  reg [31:0] memory [0:8191]; // Memory array

  wire wren;
  wire clocken0;

  assign wren = chipselect & write;
  assign clocken0 = clken & ~reset_req;

  // Memory initialization
  initial begin
      if (INIT_FILE != "") begin
          $readmemh(INIT_FILE, memory);
      end
  end

  // Write operation
  always @(posedge clk) begin
    if (clocken0) begin
      if (wren) begin
        if (byteenable[0]) memory[address][7:0] <= writedata[7:0];
        if (byteenable[1]) memory[address][15:8] <= writedata[15:8];
        if (byteenable[2]) memory[address][23:16] <= writedata[23:16];
        if (byteenable[3]) memory[address][31:24] <= writedata[31:24];
      end
      if (!wren) begin
        readdata <= memory[address];
      end
    end
  end

endmodule

