  delay1_command_valid <= command_fifo_rdreq_reg; 
  end 
  always @(posedge clk or negedge reset_n) 
  begin 
  if (reset_n == 0) 
  command_valid <= 0; 
  else 
  command_valid <= delay1_command_valid; 
  end 
 endmodule

