module origen_125687 (
    input wire [31:0] cfg_ar_addr,
    input wire [2:0] cfg_ar_prot,
    output wire cfg_ar_ready,
    input wire cfg_ar_valid,
    input wire [31:0] cfg_aw_addr,
    input wire [2:0] cfg_aw_prot,
    output wire cfg_aw_ready,
    input wire cfg_aw_valid,
    input wire cfg_b_ready,
    output wire [1:0] cfg_b_resp,
    output wire cfg_b_valid,
    output reg [63:0] cfg_r_data,
    input wire cfg_r_ready,
    output wire [1:0] cfg_r_resp,
    output wire cfg_r_valid,
    input wire [63:0] cfg_w_data,
    output wire cfg_w_ready,
    input wire [7:0] cfg_w_strb,
    input wire cfg_w_valid,
    input wire [63:0] din_data,
    input wire din_last,
    output wire din_ready,
    input wire din_valid,
    output wire [63:0] dout_data,
    output wire dout_last,
    input wire dout_ready,
    output wire dout_valid,
    input wire [63:0] headers_data,
    input wire headers_last,
    output wire headers_ready,
    input wire headers_valid,
    input wire [63:0] patternMatch_data,
    input wire patternMatch_last,
    output wire patternMatch_ready,
    input wire patternMatch_valid
);

    // Configuration registers
    reg [63:0] pattern;
    reg [63:0] mask;

    // Internal signals
    wire pattern_match;
    reg [63:0] current_packet;
    reg packet_valid;

    // Configuration interface
    assign cfg_ar_ready = 1'b1;
    assign cfg_aw_ready = 1'b1;
    assign cfg_w_ready = 1'b1;
    assign cfg_b_resp = 2'b00;
    assign cfg_b_valid = cfg_aw_valid;
    assign cfg_r_resp = 2'b00;
    assign cfg_r_valid = cfg_ar_valid;

    always @(posedge cfg_aw_valid or posedge cfg_w_valid) begin
        if (cfg_aw_addr == 32'h0000_0000 && cfg_w_valid)
            pattern <= cfg_w_data;
        else if (cfg_aw_addr == 32'h0000_0008 && cfg_w_valid)
            mask <= cfg_w_data;
    end

    always @(posedge cfg_ar_valid) begin
        if (cfg_ar_addr == 32'h0000_0000)
            cfg_r_data <= pattern;
        else if (cfg_ar_addr == 32'h0000_0008)
            cfg_r_data <= mask;
        else
            cfg_r_data <= 64'h0;
    end

    // Packet processing
    assign din_ready = dout_ready;
    assign headers_ready = dout_ready;
    assign patternMatch_ready = 1'b1;

    always @(posedge din_valid) begin
        if (din_valid && din_ready)
            current_packet <= din_data;
    end

    assign pattern_match = ((current_packet & mask) == (pattern & mask)) && packet_valid;

    always @(posedge din_valid or posedge din_last) begin
        if (din_last)
            packet_valid <= 1'b0;
        else if (din_valid && din_ready)
            packet_valid <= 1'b1;
    end

    // Output logic
    assign dout_data = pattern_match ? headers_data : 64'h0;
    assign dout_valid = pattern_match && headers_valid;
    assign dout_last = pattern_match && headers_last;

endmodule

