module autovcoder_010314 (
    ap_clk,
    ap_rst,
    ap_start,
    ap_done,
    ap_continue,
    ap_idle,
    ap_ready,
    lbRxPort_V,
    lbRxPort_V_ap_vld
);

  parameter ap_ST_fsm_state1 = 1'b1;
  parameter ap_const_lv32_0 = 32'b00000000000000000000000000000000;
  parameter ap_const_lv16_282 = 16'b1010000010;

  input ap_clk;
  input ap_rst;
  input ap_start;
  output ap_done;
  input ap_continue;
  output ap_idle;
  output ap_ready;
  output [15:0] lbRxPort_V;
  output lbRxPort_V_ap_vld;

  reg ap_done;
  reg ap_idle;
  reg ap_ready;
  reg lbRxPort_V_ap_vld;

  reg    ap_done_reg;
  (* fsm_encoding = "none" *) reg   [0:0] ap_CS_fsm;
  wire   [0:0] ap_CS_fsm_state1;
  reg   [0:0] ap_NS_fsm;

  // power-on initialization
  initial begin
    #0 ap_done_reg = 1'b0;
    #0 ap_CS_fsm = 1'b1;
  end

  always @(posedge ap_clk) begin
    if (ap_rst == 1'b1) begin
      ap_CS_fsm <= ap_ST_fsm_state1;
    end else begin
      ap_CS_fsm <= ap_NS_fsm;
    end
  end

  always @(posedge ap_clk) begin
    if (ap_rst == 1'b1) begin
      ap_done_reg <= 1'b0;
    end else begin
      if ((1'b1 == ap_continue)) begin
        ap_done_reg <= 1'b0;
      end else if (((ap_CS_fsm_state1 == 1'b1) & ~((ap_start == 1'b0) | (ap_done_reg == 1'b1)))) begin
        ap_done_reg <= 1'b1;
      end
    end
  end

  always @(*) begin
    if (((1'b1 == ap_done_reg) | ((ap_CS_fsm_state1 == 1'b1) & ~((ap_start == 1'b0) | (ap_done_reg == 1'b1))))) begin
      ap_done = 1'b1;
    end else begin
      ap_done = 1'b0;
    end
  end

  always @(*) begin
    if (((1'b0 == ap_start) & (ap_CS_fsm_state1 == 1'b1))) begin
      ap_idle = 1'b1;
    end else begin
      ap_idle = 1'b0;
    end
  end

  always @(*) begin
    if (((ap_CS_fsm_state1 == 1'b1) & ~((ap_start == 1'b0) | (ap_done_reg == 1'b1)))) begin
      ap_ready = 1'b1;
    end else begin
      ap_ready = 1'b0;
    end
  end

  always @(*) begin
    if (((ap_CS_fsm_state1 == 1'b1) & ~((ap_start == 1'b0) | (ap_done_reg == 1'b1)))) begin
      lbRxPort_V_ap_vld = 1'b1;
    end else begin
      lbRxPort_V_ap_vld = 1'b0;
    end
  end

  always @(*) begin
    case (ap_CS_fsm)
      ap_ST_fsm_state1: begin
        ap_NS_fsm = ap_ST_fsm_state1;
      end
      default: begin
        ap_NS_fsm = 'bx;
      end
    endcase
  end

  assign ap_CS_fsm_state1 = ap_CS_fsm[ap_const_lv32_0];

  assign lbRxPort_V = ap_const_lv16_282;

endmodule

