module origen_101552(
    input [15:0] displayValue,
    input [2:0] digitSelect,
    output reg [3:0] displayDigit,
    output reg [7:0] LEDs
);

    wire [3:0] thousands, hundreds, tens, ones;

    // Instantiate DigitSeparator
    DigitSeparator digit_separator (
        .value(displayValue),
        .thousands(thousands),
        .hundreds(hundreds),
        .tens(tens),
        .ones(ones)
    );

    // Instantiate FourToOneMux
    FourToOneMux four_to_one_mux (
        .thousands(thousands),
        .hundreds(hundreds),
        .tens(tens),
        .ones(ones),
        .select(digitSelect),
        .out(displayDigit)
    );

    // LED control logic
    always @(*) begin
        if (digitSelect == 3'b100) begin
            LEDs = displayValue[15:8];
        end else begin
            LEDs = 8'b0;
        end
    end

endmodule

module DigitSeparator(
    input [15:0] value,
    output reg [3:0] thousands,
    output reg [3:0] hundreds,
    output reg [3:0] tens,
    output reg [3:0] ones
);

    integer i;
    reg [15:0] temp;

    always @(*) begin
        temp = value;
        thousands = 4'd0;
        hundreds = 4'd0;
        tens = 4'd0;
        ones = 4'd0;

        for (i = 0; i < 16; i = i + 1) begin
            if (thousands >= 5)
                thousands = thousands + 3;
            if (hundreds >= 5)
                hundreds = hundreds + 3;
            if (tens >= 5)
