module origen_114582 (
    input CLOCK_50,
    input [23:0] d,
    output reg VGA_CLK,
    output reg VGA_HS,
    output reg VGA_VS,
    output reg VGA_BLANK_N,
    output reg [7:0] VGA_R,
    output reg [7:0] VGA_G,
    output reg [7:0] VGA_B,
    output reg [15:0] adr
);

    reg [3:0] reset_cnt = 0;
    reg reset = 1'b1;
    reg [9:0] h_counter = 10'd0;
    reg [9:0] v_counter = 10'd0;
    reg h_blank, v_blank;
    reg [15:0] adr_next;

    // Generate 25MHz VGA clock
    always @(posedge CLOCK_50) begin
        VGA_CLK <= ~VGA_CLK;
    end

    // Soft reset
    always @(posedge VGA_CLK) begin
        if (reset_cnt < 4'd5) begin
            reset_cnt <= reset_cnt + 1'b1;
            reset <= 1'b1;
        end else begin
            reset <= 1'b0;
        end
    end

    // Horizontal and vertical counters
    always @(posedge VGA_CLK or posedge reset) begin
        if (reset) begin
            h_counter <= 10'd0;
            v_counter <= 10'd0;
        end else begin
            if (h_counter == 10'd799) begin
                h_counter <= 10'd0;
                if (v_counter == 10'd524) begin
                    v_counter <= 10'd0;
                end else begin
                    v_counter <= v_counter + 1'b1;
                end
            end else begin
                h_counter <= h_counter + 1'b1;
            end
        end
    end

    // Sync signals
    always @(posedge VGA_CLK or posedge reset) begin
        if (reset) begin
            VGA_HS <= 1'b1;
            VGA_VS <= 1'b1;
        end else begin
            VGA_HS <= ~(h_counter >= 10'd656 && h_counter < 10'd752);
            VGA_VS <= ~(v_counter >= 10'd491 && v_counter < 10'd494);
        end
    end

    // Blanking signals
    always @(posedge VGA_CLK or posedge reset) begin
        if (reset) begin
            h_blank <= 1'b1;
            v_blank <= 1'b1;
            VGA_BLANK_N <= 1'b0;
        end else begin
            h_blank <= (h_counter < 10'd40) || (h_counter >= 10'd600);
            v_blank <= (v_counter < 10'd48) || (v_counter >= 10'd433);
            VGA_BLANK_N <= ~(h_blank || v_blank);
        end
    end

    // Color outputs
    always @(posedge VGA_CLK) begin
        if (VGA_BLANK_N) begin
            VGA_R <= d[23:16];
            VGA_G <= d[15:8];
            VGA_B <= d[7:0];
        end else begin
            VGA_R <= 8'd0;
            VGA_G <= 8'd0;
            VGA_B <= 8'd0;
        end
    end

    // Address generation
    always @(posedge VGA_CLK or posedge reset) begin
        if (reset) begin
            adr <= 16'd0;
            adr_next <= 16'd0;
        end else begin
            if (h_counter == 10'd799 && v_counter == 10'd524) begin
                adr <= 16'd0;
                adr_next <= 16'd320;
            end else if (h_counter == 10'd799) begin
                if (v_counter[0]) begin
                    adr <= adr_next;
                    adr_next <= adr + 16'd640;
                end else begin
                    adr <= adr_next;
                    adr_next <= adr + 16'd640;
                end
            end else if (h_counter < 10'd640 && v_counter < 10'd480) begin
                adr <= adr + 1'b1;
            end
        end
    end

endmodule

