module autovcoder_075433 (
    x1,
    y,
    pp_rad4_0,
    pp_rad4_1,
    pp_rad4_2,
    sign_factor
);
  // inputs
  // y multiplicand
  // x multipland 
  // P1,P2,P3 partial products
  input [15:0] y;
  input [6:0] x1;
  // output
  output [16:0] pp_rad4_0;
  output [16:0] pp_rad4_1;
  output [16:0] pp_rad4_2;
  output [2:0] sign_factor;

  wire [2:0] one, two, sign;

  code code0 (
      one[0],
      two[0],
      sign[0],
      x1[2],
      x1[1],
      x1[0]
  );
  code code1 (
      one[1],
      two[1],
      sign[1],
      x1[4],
      x1[3],
      x1[2]
  );
  code code2 (
      one[2],
      two[2],
      sign[2],
      x1[6],
      x1[5],
      x1[4]
  );


  wire [16:0] tmp1_pp;
  assign tmp1_pp = {y[15], y};  // This variable is introduced because pp has 17 bits

  // first pp generation 
  wire [17:0] out1;
  assign out1[0] = sign[0];

