            Alusrc = 1'b1;
            MemWrite = 1'b0;
            RegWrite = 1'b1;
            Jump = 1'b0;
            Extop = 1'b0;
            Aluop = 3'b000;
            r_type = 1'b0;
        end
        6'b001001: begin // ADDIU
            RegDst = 1'b0;
            Branch = 1'b0;
            MemtoReg = 1'b0;
            Alusrc = 1'b1;
            MemWrite = 1'b0;
            RegWrite = 1'b1;
            Jump = 1'b0;
            Extop = 1'b0;
            Aluop = 3'b000;
            r_type = 1'b0;
        end
        6'b001010: begin // SLT
            RegDst = 1'b1;
            Branch = 1'b0;
            MemtoReg = 1'b0;
            Alusrc = 1'b0;
            MemWrite = 1'b0;
            RegWrite = 1'b1;
            Jump = 1'b0;
            Extop = 1'b0;
            Aluop = 3'b111;
            r_type = 1'b1;
        end
