            Branch = 1'b0;
            MemtoReg = 1'b0;
            Alusrc = 1'b0;
            MemWrite = 1'b0;
            RegWrite = 1'b0;
            Jump = 1'b0;
            Extop = 1'b0;
            Aluop = 3'b000;
