  reg [4:0] ra_d;
  wire [7:0] dout;
  reg [7:0] M[19:0];
  always @(posedge clk) begin
    if (we) M[wa] <= di;
  end
  always @(posedge clk) begin
    if (re) ra_d <= ra;
  end
