    input wire D,
    output reg [15:0] Y
);

    reg [3:0] stage1_input;
    reg [3:0] stage2_input;
    reg [3:0] stage3_input;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            stage1_input <= 4'b0000;
            stage2_input <= 4'b0000;
