            // Stage 1: Input registration
            stage1_input <= {A, B, C, D};

            // Stage 2: Intermediate stage
            stage2_input <= stage1_input;

            // Stage 3: Decoding
            stage3_input <= stage2_input;

            // Output stage: Generate decoded output
            case (stage3_input)
                4'b0000: Y <= 16'h0001;
                4'b0001: Y <= 16'h0002;
                4'b0010: Y <= 16'h0004;
                4'b0011: Y <= 16'h0008;
                4'b0100: Y <= 16'h0010;
                4'b0101: Y <= 16'h0020;
                4'b0110: Y <= 16'h0040;
