                4'b1100: Y <= 16'h1000;
                4'b1101: Y <= 16'h2000;
                4'b1110: Y <= 16'h4000;
                4'b1111: Y <= 16'h8000;
                default: Y <= 16'h0000;
            endcase
        end
    end

