        count <= 3'b000;
        hCount <= 10'b0000000000;
        vCount <= 10'b0000000000;
    end
    else begin
        count <= count + 1'b1;
        if (count == 3'b100) begin
            count <= 3'b000;
            hCount <= hCount + 1'b1;
            if (hCount == 10'd800) begin
                hCount <= 10'b0000000000;
                vCount <= vCount + 1'b1;
                if (vCount == 10'd525) begin
                    vCount <= 10'b0000000000;
                end
            end
        end
    end
