            PASA_NOTA <= (PASA_NOTA == 3'd7) ? 0 : PASA_NOTA + 1;
    end

    // Note generation
    always @(posedge clock) begin
        case (PASA_NOTA)
            3'd0: begin
                if (C_NOTA == DIV_FA - 1) begin
                    C_NOTA <= 0;
                    aux <= ~aux;
                end else
                    C_NOTA <= C_NOTA + 1;
            end
            3'd1: begin
                if (C_NOTA == DIV_LA - 1) begin
                    C_NOTA <= 0;
                    aux <= ~aux;
                end else
                    C_NOTA <= C_NOTA + 1;
            end
            3'd2: begin
                if (C_NOTA == DIV_DO - 1) begin
                    C_NOTA <= 0;
                    aux <= ~aux;
                end else
                    C_NOTA <= C_NOTA + 1;
            end
            3'd3: begin
                if (C_NOTA == DIV_RE - 1) begin
                    C_NOTA <= 0;
                    aux <= ~aux;
                end else
                    C_NOTA <= C_NOTA + 1;
            end
            3'd4: begin
                if (C_NOTA == DIV_MI - 1) begin
                    C_NOTA <= 0;
                    aux <= ~aux;
                end else
                    C_NOTA <= C_NOTA + 1;
            end
            3'd5: begin
                if (C_NOTA == DIV_SOL - 1) begin
                    C_NOTA <= 0;
                    aux <= ~aux;
                end else
                    C_NOTA <= C_NOTA + 1;
            end
            3'd6: begin
                if (C_NOTA == DIV_SI - 1) begin
                    C_NOTA <= 0;
                    aux <= ~aux;
                end else
                    C_NOTA <= C_NOTA + 1;
            end
            3'd7: begin
                if (C_NOTA == DIV_DO - 1) begin
                    C_NOTA <= 0;
                    aux <= ~aux;
                end else
                    C_NOTA <= C_NOTA + 1;
