                    ld_result <= 1'b0;
                    clr_result <= 1'b0;
                    sel_muxAlu <= 1'b0;
                    sel_muxDisplay <= 1'b1;
                    clr_opCode <= 1'b0;
                    opCodeOut <= opCodeIn;
                    E0 <= 1'b0;
                    E1 <= 1'b0;
                    E2 <= 1'b1;
                    E3 <= 1'b0;
                end
                S3: begin
                    if (opCodeIn == 3'b011) begin
                        state <= S2;
                        ld_result <= 1'b1;
                        clr_result <= 1'b1;
                    end
                    else if (opCodeIn == 3'b010) begin
                        state <= S2;
                        ld_opcode <= 1'b1;
                        clr_result <= 1'b1;
                    end
                    else begin
                        state <= S3;
                        ld_result <= 1'b1;
                        clr_result <= 1'b0;
                    end
                    ld_number <= 1'b0;
                    clr_number <= 1'b0;
                    sel_muxAlu <= 1'b0;
