                    clr_opCode <= 1'b0;
                    opCodeOut <= opCodeIn;
                    E0 <= 1'b0;
                    E1 <= 1'b0;
                    E2 <= 1'b0;
                    E3 <= 1'b1;
                end
            endcase
        end
    end

