            hit <= 16'b0;
            used <= 8'b0;
        end else begin
            cache_data[0][33:18] <= mem_in;

            hit <= 16'b0;
            for (i = 0; i < 8; i = i + 1) begin
                if (cache_data[i][33:18] == mem_in) begin
                    hit[i] <= 1'b1;
                    used[i] <= 1'b1;
                end
            end

            if (hit == 16'b0) begin
                $display("miss");
            end

            if (&used) begin
                used <= 8'b0;
            end

            if (write) begin
                for (i = 0; i < 8; i = i + 1) begin
                    if (hit[i]) begin
                        if (cache_data[i][0]) begin
                            // Write-back logic (not implemented)
                        end
                        cache_data[i][17:2] <= mem_in;
                        cache_data[i][0] <= 1'b1; // Set dirty bit
                    end
                end
            end
        end
    end

    // LRU replacement logic (not fully implemented)
    assign replaceline = ~used[3:0] & used[7:4];

endmodule

